import{_ as i,o,c as n,ae as a}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"Manage Invoices (New)","description":"","frontmatter":{"title":"Manage Invoices (New)","slug":"billing-invoices-new"},"headers":[],"relativePath":"account-hub/billing-invoices-new.md","filePath":"account-hub/billing-invoices-new.md"}'),t={name:"account-hub/billing-invoices-new.md"};function r(l,e,s,c,h,v){return o(),n("div",null,[...e[0]||(e[0]=[a('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The way you view your invoices will depend on whether you are using the <a href="./branch-dashboard-overview.html">legacy</a> or <a href="./new-branch.html">new</a> Branch platform, as well as whether you are an enterprise or self-serve customer.</p><p>An invoice will be sent via email to the billing contact of your account with details of the charge and a copy of the invoice receipt.</p><h3 id="invoice-history" tabindex="-1">Invoice History <a class="header-anchor" href="#invoice-history" aria-label="Permalink to &quot;Invoice History&quot;">​</a></h3><p>Navigate to the <a href="https://branchdocs.app.link/billing-new-to-billing-settings" target="_blank" rel="noreferrer"><strong>Billing</strong></a>tab to view the <strong>Invoice history</strong> module.</p><p>The <strong>Invoice History</strong> module gives you a high-level overview of your past invoices, including:</p><ul><li>Invoice number</li><li>Invoice date</li><li>Billing period</li><li>Invoice balance</li></ul><p>This module also lets you download individual invoices using the <strong>Invoice</strong> column.</p>',8)])])}const g=i(t,[["render",r]]);export{d as __pageData,g as default};
